module bluetooth_controller (
    input [1:0] obf_command,
    output reg [2:0] status
);
    always @(*) begin
        case (obf_command)
            2'b00: status = 3'b000;
            2'b01: status = 3'b001;
            2'b10: status = 3'b010;
            2'b11: status = 3'b011;
            default: status = 3'b100; // unrecognized obf_command
        endcase
    end
endmodule
